    annotation('textbox', [xPref-0.095,  yTop, 0.25, 0.03], 'String', '(B) Preferred', ...
        'HorizontalAlignment','center','VerticalAlignment','bottom', ...
        'EdgeColor','none','FontName','Times New Roman','FontSize',12);

    % Save as true vectorial graphics with painters renderer
    % savefig(gcf, sprintf('ForceTrend_Subject%d.fig', subj));
    % exportgraphics(gcf, sprintf('ForceTrend_Subject%d.pdf', subj), 'ContentType','vector');
    % print(gcf, sprintf('ForceTrend_Subject%d.svg', subj), '-dsvg', '-painters');
end

