%% ========================================================================
%  Figure 5 stats: 2-way ANOVA (Subject x Time) + post-hoc Pre vs Post
% ========================================================================
timeCat = categorical(condIPostLabels, {'Pre','Post'});
timeNum = double(timeCat);      % 1=Pre, 2=Post
subjNum = group(:);
yPP     = all_data(:);

% ---- 2-way ANOVA with interaction ----
[pPP, tblPP, ~] = anovan(yPP, {subjNum, timeNum}, ...
    'model','interaction', ...
    'varnames', {'Subject','Time'}, ...
    'display','off');

% Parse ANOVA table
hdr  = string(tblPP(1,:));
rows = strtrim(string(tblPP(2:end,1)));

colSS = find(contains(hdr,'Sum Sq','IgnoreCase',true),1);
colDF = find(contains(hdr,'d.f','IgnoreCase',true) | strcmpi(strtrim(hdr),'DF'),1);
colMS = find(contains(hdr,'Mean Sq','IgnoreCase',true),1);
colF  = find(strcmpi(strtrim(hdr),'F'),1);
colP  = find(contains(hdr,'Prob>F','IgnoreCase',true),1);

idxSubj = find(strcmpi(rows,'Subject'),1);
idxTime = find(strcmpi(rows,'Time'),1);
idxInt  = find(contains(lower(rows),'subject') & contains(lower(rows),'time') & ...
               ~strcmpi(rows,'Subject') & ~strcmpi(rows,'Time'), 1);
idxErr  = find(strcmpi(rows,'Error'),1);

factors = ["Subject"; "Time"; "Subject*Time"];
idxRows = [idxSubj; idxTime; idxInt];

SS = nan(3,1); DF = nan(3,1); MS = nan(3,1); Fv = nan(3,1); Pv = nan(3,1); etaP = nan(3,1);

SSerr = NaN;
if ~isempty(idxErr) && ~isempty(colSS)
    SSerr = local_cell2num(tblPP{idxErr+1,colSS});
end

for k = 1:3
    if isempty(idxRows(k)), continue; end
    rr = idxRows(k)+1;
    if ~isempty(colSS), SS(k) = local_cell2num(tblPP{rr,colSS}); end
    if ~isempty(colDF), DF(k) = local_cell2num(tblPP{rr,colDF}); end
    if ~isempty(colMS), MS(k) = local_cell2num(tblPP{rr,colMS}); end
    if ~isempty(colF),  Fv(k) = local_cell2num(tblPP{rr,colF});  end
    if ~isempty(colP),  Pv(k) = local_cell2num(tblPP{rr,colP});  else, Pv(k) = pPP(k); end

    if ~isnan(SS(k)) && ~isnan(SSerr) && (SS(k)+SSerr)>0
        etaP(k) = SS(k)/(SS(k)+SSerr); % partial eta^2
    end
end

ANOVA_PrePost = table(factors, SS, DF, MS, Fv, Pv, etaP, ...
    'VariableNames', {'Factor','SS','DF','MS','F','P_Value','PartialEtaSq'});

disp('=== Figure 5 ANOVA (Subject x Time) ===');
disp(ANOVA_PrePost);

% ---- Post-hoc: Pre vs Post within each subject (Bonferroni corrected) ----
alpha = 0.05;
m = Nsubj; % 9 comparisons

Subject = (1:Nsubj).';
N1_Pre = nan(Nsubj,1); N2_Post = nan(Nsubj,1);
Mean1_Pre = nan(Nsubj,1); Mean2_Post = nan(Nsubj,1);
MeanDiff_PreMinusPost = nan(Nsubj,1);
T_Statistic = nan(Nsubj,1); DF_t = nan(Nsubj,1);
CI95Bonf_Lower = nan(Nsubj,1); CI95Bonf_Upper = nan(Nsubj,1);
P_Raw = nan(Nsubj,1); P_Bonferroni = nan(Nsubj,1);
Significant = false(Nsubj,1); Cohens_d = nan(Nsubj,1);

for subj = 1:Nsubj
    xPre  = sqrt(sum(MVF_i_data{subj}.data_trim(:,1:3).^2,2));
    xPost = sqrt(sum(MVF_f_data{subj}.data_trim(:,1:3).^2,2));

    N1_Pre(subj) = numel(xPre);
    N2_Post(subj) = numel(xPost);
    Mean1_Pre(subj) = mean(xPre,'omitnan');
    Mean2_Post(subj) = mean(xPost,'omitnan');
    MeanDiff_PreMinusPost(subj) = Mean1_Pre(subj) - Mean2_Post(subj);

    [~, p0, ~, st] = ttest2(xPre, xPost, 'Tail','both', 'Vartype','equal', 'Alpha',alpha);
    [~, ~, ciB]    = ttest2(xPre, xPost, 'Tail','both', 'Vartype','equal', 'Alpha',alpha/m);

    P_Raw(subj) = p0;
    P_Bonferroni(subj) = min(p0*m, 1);
    Significant(subj) = P_Bonferroni(subj) < alpha;

    T_Statistic(subj) = st.tstat;
    DF_t(subj) = st.df;
    CI95Bonf_Lower(subj) = ciB(1);
    CI95Bonf_Upper(subj) = ciB(2);

    Cohens_d(subj) = local_cohens_d(xPre, xPost);
end

PostHoc_PrePost = table(Subject, N1_Pre, N2_Post, Mean1_Pre, Mean2_Post, MeanDiff_PreMinusPost, ...
    T_Statistic, DF_t, CI95Bonf_Lower, CI95Bonf_Upper, P_Raw, P_Bonferroni, Significant, Cohens_d, ...
    'VariableNames', {'Subject','N1_Pre','N2_Post','Mean1_Pre','Mean2_Post','MeanDiff_PreMinusPost', ...
                      'T_Statistic','DF','CI95Bonf_Lower','CI95Bonf_Upper','P_Raw','P_Bonferroni','Significant','Cohens_d'});

disp('=== Figure 5 Post-hoc (Pre vs Post within subject) ===');
disp(PostHoc_PrePost);

