%% ========================================================================
%  LOCAL FUNCTIONS – used by perform_anova_analysis
% ========================================================================

function [posthocTable, anovaTable, descriptivesTable] = perform_anova_analysis(dataset, subj, flag)
    % Subject-level 2-way ANOVA (Condition x Task) + Bonferroni post hoc.
    % Outputs:
    %   posthocTable      -> pairwise comparisons with t, df, CI, p, effect size
    %   anovaTable        -> ANOVA factors with SS, df, MS, F, p, partial eta^2
    %   descriptivesTable -> per cell summary stats (n, mean, SD, SEM, median, IQR, min, max)

    task_labels = {'FLAT', 'LCK', 'FEX', 'FEXURD', 'ULCK'};
    cond_labels = {'CN', 'UCN'};
    alpha = 0.05;

    switch flag
        case 1, metricLabel = "Fmag";
        case 2, metricLabel = "Fz";
        case 3, metricLabel = "TrialMeanFmag";
        otherwise, metricLabel = "Unknown";
    end

    allData   = [];
    groupCond = [];
    groupTask = [];
    data_map  = containers.Map(); % key: 'CN_FLAT', etc.

    % -------- Build pooled data and descriptives --------
    desc_subj = [];
    desc_metric = strings(0,1);
    desc_cond = strings(0,1);
    desc_task = strings(0,1);
    desc_n = [];
    desc_mean = []; desc_sd = []; desc_sem = [];
    desc_median = []; desc_iqr = []; desc_min = []; desc_max = [];

    numCond = 2; numTask = 5; numTrials = 5;

    for cond = 1:numCond
        for t = 1:numTask
            pooledData = [];

            for trial = 1:numTrials
                D = dataset{subj,cond,t,trial};
                if isempty(D) || ~isfield(D,'data_trim') || isempty(D.data_trim)
                    continue
                end

                if flag == 1
                    f_tot = sqrt(sum(D.data_trim(:,1:3).^2,2));
                elseif flag == 2
                    f_tot = -D.data_trim(:,3);
                elseif flag == 3
                    f_tot = mean(sqrt(sum(D.data_trim(:,1:3).^2,2))); % one value per trial
                else
                    f_tot = [];
                end

                pooledData = [pooledData; f_tot(:)]; %#ok<AGROW>
            end

            pooledData = pooledData(~isnan(pooledData));
            key = sprintf('%s_%s', cond_labels{cond}, task_labels{t});
            data_map(key) = pooledData;

            if ~isempty(pooledData)
                allData   = [allData; pooledData]; %#ok<AGROW>
                groupCond = [groupCond; repmat(cond, numel(pooledData), 1)]; %#ok<AGROW>
                groupTask = [groupTask; repmat(t,    numel(pooledData), 1)]; %#ok<AGROW>
            end

            % descriptives (always create row)
            n = numel(pooledData);
            if n > 0
                mu = mean(pooledData,'omitnan');
                sdv = std(pooledData,0,'omitnan');
                semv = sdv / sqrt(n);
                medv = median(pooledData,'omitnan');
                iqrv = iqr(pooledData);
                mnv = min(pooledData);
                mxv = max(pooledData);
            else
                mu = NaN; sdv = NaN; semv = NaN; medv = NaN; iqrv = NaN; mnv = NaN; mxv = NaN;
            end

            desc_subj(end+1,1)   = subj; %#ok<AGROW>
            desc_metric(end+1,1) = metricLabel; %#ok<AGROW>
            desc_cond(end+1,1)   = string(cond_labels{cond}); %#ok<AGROW>
            desc_task(end+1,1)   = string(task_labels{t}); %#ok<AGROW>
            desc_n(end+1,1)      = n; %#ok<AGROW>
            desc_mean(end+1,1)   = mu; %#ok<AGROW>
            desc_sd(end+1,1)     = sdv; %#ok<AGROW>
            desc_sem(end+1,1)    = semv; %#ok<AGROW>
            desc_median(end+1,1) = medv; %#ok<AGROW>
            desc_iqr(end+1,1)    = iqrv; %#ok<AGROW>
            desc_min(end+1,1)    = mnv; %#ok<AGROW>
            desc_max(end+1,1)    = mxv; %#ok<AGROW>
        end
    end

    descriptivesTable = table(desc_subj, desc_metric, desc_cond, desc_task, ...
        desc_n, desc_mean, desc_sd, desc_sem, desc_median, desc_iqr, desc_min, desc_max, ...
        'VariableNames', {'Subject','Metric','Condition','Task','N','Mean','SD','SEM','Median','IQR','Min','Max'});

    % -------- ANOVA --------
    if isempty(allData) || numel(unique(groupCond)) < 2 || numel(unique(groupTask)) < 2
        anovaTable = table;
    else
        [p, tbl, stats] = anovan(allData, {groupCond, groupTask}, ...
            'model','interaction', 'varnames', {'Condition','Task'}, 'display','off'); %#ok<ASGLU>

        headers = string(tbl(1,:));
        rowNames = string(tbl(2:end,1)); rowNames = strtrim(rowNames);

        colSS = find(contains(headers,'Sum Sq','IgnoreCase',true),1);
        colDF = find(contains(headers,'d.f','IgnoreCase',true) | strcmpi(strtrim(headers),'DF'),1);
        colMS = find(contains(headers,'Mean Sq','IgnoreCase',true),1);
        colF  = find(strcmpi(strtrim(headers),'F'),1);
        if isempty(colF), colF = find(contains(headers,'F','IgnoreCase',true),1); end
        colP  = find(contains(headers,'Prob>F','IgnoreCase',true),1);

        idxCond = find(strcmpi(rowNames,'Condition'),1);
        idxTask = find(strcmpi(rowNames,'Task'),1);
        idxInter = find(contains(lower(rowNames),'condition') & contains(lower(rowNames),'task') ...
                     & ~strcmpi(rowNames,'Condition') & ~strcmpi(rowNames,'Task'),1);
        idxErr = find(strcmpi(rowNames,'Error'),1);

        SS_error = NaN;
        if ~isempty(idxErr) && ~isempty(colSS)
            SS_error = local_cell2num(tbl{idxErr+1,colSS});
        end

        factors = {'Condition'; 'Task'; 'Condition*Task'};
        idxRows = [idxCond; idxTask; idxInter];

        SS = nan(3,1); DF = nan(3,1); MS = nan(3,1); Fv = nan(3,1); Pv = nan(3,1); etaP = nan(3,1);
        for k = 1:3
            r = idxRows(k);
            if isempty(r), continue; end
            rr = r + 1; % tbl has header row

            if ~isempty(colSS), SS(k) = local_cell2num(tbl{rr,colSS}); end
            if ~isempty(colDF), DF(k) = local_cell2num(tbl{rr,colDF}); end
            if ~isempty(colMS), MS(k) = local_cell2num(tbl{rr,colMS}); end
            if ~isempty(colF),  Fv(k) = local_cell2num(tbl{rr,colF});  end
            if ~isempty(colP),  Pv(k) = local_cell2num(tbl{rr,colP});  else, Pv(k) = p(k); end

            if ~isnan(SS(k)) && ~isnan(SS_error) && (SS(k)+SS_error)>0
                etaP(k) = SS(k)/(SS(k)+SS_error); % partial eta^2
            end
        end

        anovaTable = table( ...
            repmat(subj,3,1), repmat(metricLabel,3,1), string(factors), ...
            SS, DF, MS, Fv, Pv, etaP, ...
            'VariableNames', {'Subject','Metric','Factor','SS','DF','MS','F','P_Value','PartialEtaSq'});
    end

    % -------- Build list of requested post hoc comparisons --------
    % 1) same condition, different task
    C = []; % [cond1 task1 cond2 task2]
    cmpType = strings(0,1);

    for cond = 1:2
        for t1 = 1:4
            for t2 = t1+1:5
                C(end+1,:) = [cond t1 cond t2]; %#ok<AGROW>
                cmpType(end+1,1) = "WithinCondition"; %#ok<AGROW>
            end
        end
    end

    % 2) same task, different condition (CN vs UCN)
    for t = 1:5
        C(end+1,:) = [1 t 2 t]; %#ok<AGROW>
        cmpType(end+1,1) = "BetweenCondition"; %#ok<AGROW>
    end

    nCmp = size(C,1);

    % determine available comparisons for Bonferroni m
    available = false(nCmp,1);
    for i = 1:nCmp
        c1 = C(i,1); t1 = C(i,2); c2 = C(i,3); t2 = C(i,4);
        k1 = sprintf('%s_%s', cond_labels{c1}, task_labels{t1});
        k2 = sprintf('%s_%s', cond_labels{c2}, task_labels{t2});
        if isKey(data_map,k1) && isKey(data_map,k2)
            x = data_map(k1); y = data_map(k2);
            available(i) = numel(x)>=2 && numel(y)>=2;
        end
    end
    m = sum(available); % number of tests actually performed
    if m == 0, m = 1; end

    % -------- Post hoc table --------
    Group1 = strings(nCmp,1);
    Group2 = strings(nCmp,1);
    N1 = nan(nCmp,1); N2 = nan(nCmp,1);
    Mean1 = nan(nCmp,1); Mean2 = nan(nCmp,1);
    MeanDiff = nan(nCmp,1);
    T_stat = nan(nCmp,1); DF_t = nan(nCmp,1);
    CI95_L = nan(nCmp,1); CI95_U = nan(nCmp,1);
    CI95Bonf_L = nan(nCmp,1); CI95Bonf_U = nan(nCmp,1);
    P_raw = nan(nCmp,1); P_bonf = nan(nCmp,1);
    Significant = false(nCmp,1);
    Cohens_d = nan(nCmp,1);
    DataAvailable = false(nCmp,1);

    for i = 1:nCmp
        c1 = C(i,1); t1 = C(i,2); c2 = C(i,3); t2 = C(i,4);

        Group1(i) = sprintf('%s - %s', cond_labels{c1}, task_labels{t1});
        Group2(i) = sprintf('%s - %s', cond_labels{c2}, task_labels{t2});

        k1 = sprintf('%s_%s', cond_labels{c1}, task_labels{t1});
        k2 = sprintf('%s_%s', cond_labels{c2}, task_labels{t2});
        if ~(isKey(data_map,k1) && isKey(data_map,k2)), continue; end

        x = data_map(k1); y = data_map(k2);
        x = x(~isnan(x)); y = y(~isnan(y));

        N1(i) = numel(x); N2(i) = numel(y);
        Mean1(i) = mean(x,'omitnan');
        Mean2(i) = mean(y,'omitnan');
        MeanDiff(i) = Mean1(i) - Mean2(i);

        if numel(x) < 2 || numel(y) < 2
            continue
        end

        DataAvailable(i) = true;

        % two-sided t-test (equal variances, consistent with ANOVA-style pooling)
        [~, p0, ci0, st0] = ttest2(x, y, 'Tail','both', 'Vartype','equal', 'Alpha',alpha);
        [~, ~, ciB, ~]    = ttest2(x, y, 'Tail','both', 'Vartype','equal', 'Alpha',alpha/m);

        P_raw(i)   = p0;
        P_bonf(i)  = min(p0*m, 1);
        Significant(i) = P_bonf(i) < alpha;

        T_stat(i) = st0.tstat;
        DF_t(i)   = st0.df;
        CI95_L(i) = ci0(1); CI95_U(i) = ci0(2);
        CI95Bonf_L(i) = ciB(1); CI95Bonf_U(i) = ciB(2);

        Cohens_d(i) = local_cohens_d(x, y);
    end

    posthocTable = table( ...
        repmat(subj,nCmp,1), repmat(metricLabel,nCmp,1), cmpType, ...
        Group1, Group2, DataAvailable, ...
        N1, N2, Mean1, Mean2, MeanDiff, ...
        T_stat, DF_t, ...
        CI95_L, CI95_U, CI95Bonf_L, CI95Bonf_U, ...
        P_raw, P_bonf, Significant, Cohens_d, ...
        'VariableNames', {'Subject','Metric','ComparisonType','Group1','Group2','DataAvailable', ...
                          'N1','N2','Mean1','Mean2','MeanDiff', ...
                          'T_Statistic','DF','CI95_Lower','CI95_Upper','CI95Bonf_Lower','CI95Bonf_Upper', ...
                          'P_Raw','P_Bonferroni','Significant','Cohens_d'});
end

function v = local_cell2num(x)
    if isnumeric(x)
        v = x;
    elseif isstring(x) || ischar(x)
        v = str2double(x);
    else
        v = NaN;
    end
end

function d = local_cohens_d(x, y)
    % Try robust Cohen's d if meanEffectSize is available; else classic d.
    d = NaN;
    try
        if exist('meanEffectSize','file') == 2
            T = meanEffectSize(x, y, Effect="robustcohen");
            d = T.Effect;
            return;
        end
    catch
        % fall through to classic d
    end
    % classic pooled SD Cohen's d
    x = x(~isnan(x)); y = y(~isnan(y));
    nx = numel(x); ny = numel(y);
    sx = std(x,0);   sy = std(y,0);
    sp = sqrt(((nx-1)*sx^2 + (ny-1)*sy^2) / (nx+ny-2));
    d  = (mean(x) - mean(y)) / sp;
end
